	},{
		root:root,
		threshold:[0],
		rootMargin:"0px0px500px0px"
	})

imgs=document.getElementsByTagName('img')
Array.from(imgs).forEach(item=>{
		lazy.observe(item)
	})

//查看大图插件
newViewer(root,{title:false,interval:3000})
</script>

