function getInput(){
var str=$("#input").value;
var list = parseToDOM(str);
if(list.length==0){
	$("#input").placeholder = "格式化失败！！！请检查是否为带html标签的文本"
	}else{

var html = "";
for (let i=0;i<list.length;i++){
	let text = list[i].innerText;
	let href = list[i].getAttribute("href");
	html += text + "::" + href +"\n"
	}
$("#input").value = html
}
}

function getInput2(){
var str=$("#input").value;
var list = parseToDOM(str);
if(list.length==0){
	$("#input").placeholder = "格式化失败！！！请检查是否为带html标签的文本"
	}else{
var html = [];
for (let i=0;i<list.length;i++){
	let text = list[i].innerText;
	let href = list[i].getAttribute("href");
	html.push({
		title:text,
		url : href
		})
	}
$("#input").value = JSON.stringify(html)
}
}

function getInput3(){
text=$("#input").value;
if(text.match(/\&\&|::/g)){
text=text.replace(/\&\&/g,'\n');
list=text.match(/.*::.*/g);
html=[];
for(i=0;i<list.length;i++){
l=list[i].match(/(.*)::(.*)/);
title=l[1];url=l[2]
html.push({
title:title,
url:url
})
}
$("#input").value=JSON.stringify(html)
}else{
html="";
json=eval(text);
for(i in json){
html+=json[i].title+"::"+json[i].url+"\n"
}
$("#input").value=html
}
}


function getInput4(flag,x){
